import React, { useState, useEffect } from 'react';

export default function Carousel({ slides, interval = 3000 }) {
  const [index, setIndex] = useState(0);
  const [paused, setPaused] = useState(false);

  const next = () => setIndex((i) => (i + 1) % slides.length);
  const prev = () => setIndex((i) => (i - 1 + slides.length) % slides.length);

  useEffect(() => {
    if (paused || slides.length <= 1) return;
    const id = setInterval(() => setIndex((i) => (i + 1) % slides.length), interval);
    return () => clearInterval(id);
  }, [paused, slides.length, interval]);

  const arrow = {
    position: 'absolute',
    top: '50%',
    transform: 'translateY(-50%)',
    border: 'none',
    background: 'rgba(0,0,0,0.4)',
    color: '#fff',
    width: 36,
    height: 36,
    borderRadius: '50%',
    cursor: 'pointer',
    fontSize: 18,
  };

  return (
    <div
      style={{ position: 'relative', width: 360, maxWidth: '100%', overflow: 'hidden', borderRadius: 12 }}
      onMouseEnter={() => setPaused(true)}
      onMouseLeave={() => setPaused(false)}
    >
      <div style={{ display: 'flex', transform: `translateX(${-index * 100}%)`, transition: 'transform 0.4s ease' }}>
        {slides.map((s) => (
          <div
            key={s.id}
            style={{ minWidth: '100%', height: 200, background: s.color, color: '#fff', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 24, fontWeight: 700 }}
          >
            {s.label}
          </div>
        ))}
      </div>

      {slides.length > 1 && (
        <>
          <button style={{ ...arrow, left: 8 }} onClick={prev} aria-label="Previous">‹</button>
          <button style={{ ...arrow, right: 8 }} onClick={next} aria-label="Next">›</button>
          <div style={{ position: 'absolute', bottom: 10, left: 0, right: 0, display: 'flex', justifyContent: 'center', gap: 8 }}>
            {slides.map((_, i) => (
              <button
                key={i}
                onClick={() => setIndex(i)}
                aria-label={`Go to slide ${i + 1}`}
                aria-current={i === index}
                style={{ width: 10, height: 10, borderRadius: '50%', border: 'none', cursor: 'pointer', background: i === index ? '#fff' : 'rgba(255,255,255,0.5)' }}
              />
            ))}
          </div>
        </>
      )}
    </div>
  );
}

