import { Component, Input, OnInit, OnDestroy } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

interface Slide { id: number; color: string; label: string; }

@Component({
  selector: 'app-carousel',
  template: `
    <div
      style="position: relative; width: 360px; max-width: 100%; overflow: hidden; border-radius: 12px;"
      (mouseenter)="paused = true"
      (mouseleave)="paused = false"
    >
      <div style="display: flex; transition: transform 0.4s ease;" [style.transform]="'translateX(' + (-index * 100) + '%)'">
        <div
          *ngFor="let s of slides"
          [style.background]="s.color"
          style="min-width: 100%; height: 200px; color: #fff; display: flex; align-items: center; justify-content: center; font-size: 24px; font-weight: 700;"
        >{{ s.label }}</div>
      </div>

      <ng-container *ngIf="slides.length > 1">
        <button (click)="prev()" aria-label="Previous" style="position: absolute; top: 50%; left: 8px; transform: translateY(-50%); border: none; background: rgba(0,0,0,0.4); color: #fff; width: 36px; height: 36px; border-radius: 50%; cursor: pointer; font-size: 18px;">‹</button>
        <button (click)="next()" aria-label="Next" style="position: absolute; top: 50%; right: 8px; transform: translateY(-50%); border: none; background: rgba(0,0,0,0.4); color: #fff; width: 36px; height: 36px; border-radius: 50%; cursor: pointer; font-size: 18px;">›</button>
        <div style="position: absolute; bottom: 10px; left: 0; right: 0; display: flex; justify-content: center; gap: 8px;">
          <button
            *ngFor="let s of slides; let i = index"
            (click)="index = i"
            [attr.aria-current]="i === index"
            [attr.aria-label]="'Go to slide ' + (i + 1)"
            [style.background]="i === index ? '#fff' : 'rgba(255,255,255,0.5)'"
            style="width: 10px; height: 10px; border-radius: 50%; border: none; cursor: pointer;"
          ></button>
        </div>
      </ng-container>
    </div>
  `,
})
export class CarouselComponent implements OnInit, OnDestroy {
  @Input() slides: Slide[] = [];
  @Input() interval = 3000;
  index = 0;
  paused = false;
  private timer: any = null;

  next(): void {
    this.index = (this.index + 1) % this.slides.length;
  }

  prev(): void {
    this.index = (this.index - 1 + this.slides.length) % this.slides.length;
  }

  ngOnInit(): void {
    this.timer = setInterval(() => {
      if (!this.paused && this.slides.length > 1) {
        this.next();
      }
    }, this.interval);
  }

  ngOnDestroy(): void {
    clearInterval(this.timer);
  }
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px;">
      <h1>Carousel Demo</h1>
      <app-carousel [slides]="slides"></app-carousel>
    </div>
  `,
})
export class AppComponent {
  slides: Slide[] = [
    { id: 1, color: '#2563eb', label: 'Slide 1' },
    { id: 2, color: '#16a34a', label: 'Slide 2' },
    { id: 3, color: '#d97706', label: 'Slide 3' },
    { id: 4, color: '#dc2626', label: 'Slide 4' },
  ];
}

@NgModule({
  declarations: [AppComponent, CarouselComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
